command:
export PATH="/usr/local/cuda/bin:$${PATH:-}"; export CUDA_HOME="$${CUDA_HOME:-/usr/local/cuda}"; export CUDA_PATH="$${CUDA_PATH:-$${CUDA_HOME}}"; export CUDAToolkit_ROOT="$${CUDAToolkit_ROOT:-$${CUDA_HOME}}"; export LD_LIBRARY_PATH="/usr/local/cuda/lib64:$${LD_LIBRARY_PATH:-}"; MODEL_LOADER_EXTRA_CONFIG='{}'; if [[ "$${DSPARK_WEIGHT_LOAD_FORMAT:-auto}" == "roce_tp" ]]; then
  MODEL_LOADER_EXTRA_CONFIG="{\"buffer_size_mb\":$${DSPARK_ROCE_LOAD_BUFFER_MB:-256}}";
fi; KV_CACHE_ARGS=(); if [[ -n "$${KV_CACHE_MEMORY_BYTES:-}" ]]; then
  if [[ ! "$${KV_CACHE_MEMORY_BYTES}" =~ ^[1-9][0-9]*$$ ]]; then
    printf 'Invalid KV_CACHE_MEMORY_BYTES=%q; expected a positive integer\n' "$${KV_CACHE_MEMORY_BYTES}" >&2;
    exit 64;
  fi;
  KV_CACHE_ARGS=(--kv-cache-memory-bytes "$${KV_CACHE_MEMORY_BYTES}");
fi; SPECULATIVE_ARGS=(); case "$${DSPARK_SPECULATION_MODE:-dspark}" in
  dspark)
    SPECULATIVE_CONFIG="{\"method\":\"dspark\",\"model\":\"/models/dspark-draft\",\"num_speculative_tokens\":5,\"draft_sample_method\":\"probabilistic\"}";
    SPECULATIVE_ARGS=(--speculative-config "$${SPECULATIVE_CONFIG}");
    MAX_CUDAGRAPH_CAPTURE_SIZE=$$(( 12 * (5 + 1) ));
    ;;
  off)
    MAX_CUDAGRAPH_CAPTURE_SIZE=12;
    ;;
  *)
    printf 'Invalid DSPARK_SPECULATION_MODE=%q; expected dspark or off\n' "$${DSPARK_SPECULATION_MODE}" >&2;
    exit 64;
    ;;
esac; exec /usr/local/bin/vllm serve /models/dsv4-abliterated --served-model-name deepseek-v4-flash-nvfp4-dspark --host 0.0.0.0 --port 8888 --trust-remote-code --load-format "$${DSPARK_WEIGHT_LOAD_FORMAT:-auto}" --model-loader-extra-config "$${MODEL_LOADER_EXTRA_CONFIG}" --tensor-parallel-size 2 --pipeline-parallel-size 1 --kv-cache-dtype nvfp4_ds_mla --block-size 256 --max-model-len 350000 --max-num-seqs 12 --max-num-batched-tokens 8192 --max-cudagraph-capture-size "$${MAX_CUDAGRAPH_CAPTURE_SIZE}" --gpu-memory-utilization 0.78 "$${KV_CACHE_ARGS[@]}" --enable-prefix-caching --async-scheduling --enable-chunked-prefill "$${SPECULATIVE_ARGS[@]}" --tokenizer-mode deepseek_v4 --distributed-executor-backend mp --moe-backend flashinfer_cutlass --tool-call-parser deepseek_v4 --enable-auto-tool-choice --reasoning-parser deepseek_v4 --reasoning-config '{"reasoning_parser":"deepseek_v4","reasoning_start_str":"<think>","reasoning_end_str":"</think>"}' --default-chat-template-kwargs '{"thinking":false}' --generation-config vllm --enable-flashinfer-autotune --nnodes 2 --node-rank 0 --master-addr 10.200.0.1 --master-port 25000 --jit-monitor-mode warn --jit-monitor-verbose
